package com.chaobo.scm.supplier.infrastructure.persistence.asn;import org.apache.ibatis.annotations.*;import java.time.*;
@Mapper public interface AsnTransportFactMapper{@Insert("INSERT INTO sup_asn_transport_fact(asn_id,shipment_id,waybill_no,carrier_code,transport_status,last_node,last_track_at,exception_code,exception_reason,source_version) VALUES(#{asnId},#{shipmentId},#{waybillNo},#{carrierCode},#{status},#{node},#{occurredAt},#{exceptionCode},#{exceptionReason},#{sourceVersion}) ON DUPLICATE KEY UPDATE shipment_id=IF(VALUES(source_version)>source_version,VALUES(shipment_id),shipment_id),waybill_no=IF(VALUES(source_version)>source_version,VALUES(waybill_no),waybill_no),carrier_code=IF(VALUES(source_version)>source_version,VALUES(carrier_code),carrier_code),transport_status=IF(VALUES(source_version)>source_version,VALUES(transport_status),transport_status),last_node=IF(VALUES(source_version)>source_version,VALUES(last_node),last_node),last_track_at=IF(VALUES(source_version)>source_version,VALUES(last_track_at),last_track_at),exception_code=IF(VALUES(source_version)>source_version,VALUES(exception_code),exception_code),exception_reason=IF(VALUES(source_version)>source_version,VALUES(exception_reason),exception_reason),source_version=GREATEST(source_version,VALUES(source_version))")void upsert(@Param("asnId")long asnId,@Param("shipmentId")Long shipmentId,@Param("waybillNo")String waybillNo,@Param("carrierCode")String carrierCode,@Param("status")int status,@Param("node")String node,@Param("occurredAt")OffsetDateTime occurredAt,@Param("exceptionCode")String exceptionCode,@Param("exceptionReason")String exceptionReason,@Param("sourceVersion")long sourceVersion);}
